import{_ as n,c as a,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Mehrkanal-Systeme & Plattformen | Clawdbot-Tutorial","description":"Lernen Sie, wie Sie das Mehrkanal-System von Clawdbot konfigurieren und verwenden, einschließlich WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS und Android.","frontmatter":{"title":"Mehrkanal-Systeme & Plattformen | Clawdbot-Tutorial","sidebarTitle":"Integration gängiger Chat-Tools","subtitle":"Mehrkanal-Systeme & Plattformen","description":"Lernen Sie, wie Sie das Mehrkanal-System von Clawdbot konfigurieren und verwenden, einschließlich WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS und Android.","tags":["Kanäle","Plattformen","Integration"],"order":60},"headers":[],"relativePath":"de/moltbot/moltbot/platforms/index.md","filePath":"de/moltbot/moltbot/platforms/index.md"}'),t={name:"de/moltbot/moltbot/platforms/index.md"};function l(s,e,o,d,h,g){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="mehrkanal-systeme-plattformen" tabindex="-1">Mehrkanal-Systeme &amp; Plattformen <a class="header-anchor" href="#mehrkanal-systeme-plattformen" aria-label="Permalink to &quot;Mehrkanal-Systeme &amp; Plattformen&quot;">​</a></h1><p>Clawdbot unterstützt über die einheitliche Gateway-Kontrollebene verschiedene Kommunikationskanäle und Plattformen, sodass Sie auf einer vertrauten Oberfläche mit Ihrem AI-Assistenten interagieren können.</p><h2 id="kapitelubersicht" tabindex="-1">Kapitelübersicht <a class="header-anchor" href="#kapitelubersicht" aria-label="Permalink to &quot;Kapitelübersicht&quot;">​</a></h2><p>In diesem Kapitel werden alle von Clawdbot unterstützten Kommunikationskanäle und Plattformen vorgestellt, darunter Instant-Messaging-Anwendungen (WhatsApp, Telegram, Slack, Discord usw.), mobile Nodes (iOS, Android) und Desktop-Anwendungen (macOS). Erfahren Sie, wie Sie diese Kanäle konfigurieren, damit der AI-Assistent nahtlos in Ihren täglichen Arbeitsablauf integriert wird.</p><h2 id="unterseitennavigation" tabindex="-1">Unterseitennavigation <a class="header-anchor" href="#unterseitennavigation" aria-label="Permalink to &quot;Unterseitennavigation&quot;">​</a></h2><h3 id="kanalubersicht" tabindex="-1">Kanalübersicht <a class="header-anchor" href="#kanalubersicht" aria-label="Permalink to &quot;Kanalübersicht&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Übersicht des Mehrkanal-Systems</a></strong> - Erfahren Sie mehr über alle von Clawdbot unterstützten Kommunikationskanäle und deren Funktionen sowie die grundlegenden Konzepte der Kanalkonfiguration.</li></ul><h3 id="instant-messaging-kanale" tabindex="-1">Instant-Messaging-Kanäle <a class="header-anchor" href="#instant-messaging-kanale" aria-label="Permalink to &quot;Instant-Messaging-Kanäle&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Konfigurieren und verwenden Sie den WhatsApp-Kanal (basierend auf Baileys) mit Unterstützung für Geräteverbindung und Gruppenverwaltung.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Konfigurieren und verwenden Sie den Telegram-Kanal (basierend auf grammY Bot API) mit Einrichtung von Bot-Token und Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Konfigurieren und verwenden Sie den Slack-Kanal (basierend auf Bolt) für die Integration in Ihren Arbeitsbereich.</li><li><strong><a href="./discord/">Discord</a></strong> - Konfigurieren und verwenden Sie den Discord-Kanal (basierend auf discord.js) mit Unterstützung für Server und Kanäle.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Konfigurieren und verwenden Sie den Google Chat-Kanal für die Integration mit Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Konfigurieren und verwenden Sie den Signal-Kanal (basierend auf signal-cli) für privatsphäreschützende Kommunikation.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Konfigurieren und verwenden Sie den iMessage-Kanal (macOS-exklusiv) für die Integration mit der macOS-Nachrichten-App.</li><li><strong><a href="./line/">LINE</a></strong> - Konfigurieren und verwenden Sie den LINE-Kanal (Messaging API) für die Interaktion mit LINE-Benutzern.</li></ul><h3 id="web-native-anwendungen" tabindex="-1">Web &amp; Native Anwendungen <a class="header-anchor" href="#web-native-anwendungen" aria-label="Permalink to &quot;Web &amp; Native Anwendungen&quot;">​</a></h3><ul><li><strong><a href="./webchat/">WebChat-Oberfläche</a></strong> - Verwenden Sie die integrierte WebChat-Oberfläche zur Interaktion mit dem AI-Assistenten, ohne externe Kanäle konfigurieren zu müssen.</li><li><strong><a href="./macos-app/">macOS-Anwendung</a></strong> - Erfahren Sie mehr über die Funktionen der macOS-Menüleistenanwendung, einschließlich Voice Wake, Talk Mode und Fernsteuerung.</li><li><strong><a href="./ios-node/">iOS-Node</a></strong> - Konfigurieren Sie die iOS-Node zur Ausführung lokaler Geräteoperationen (Camera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Android-Node</a></strong> - Konfigurieren Sie die Android-Node zur Ausführung lokaler Geräteoperationen (Camera, Canvas).</li></ul><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><p>Je nach Ihrem Anwendungsfall wird die folgende Lernreihenfolge empfohlen:</p><h3 id="schnelleinsteigung-fur-anfanger" tabindex="-1">Schnelleinsteigung für Anfänger <a class="header-anchor" href="#schnelleinsteigung-fur-anfanger" aria-label="Permalink to &quot;Schnelleinsteigung für Anfänger&quot;">​</a></h3><p>Wenn Sie Clawdbot zum ersten Mal verwenden, wird empfohlen, die folgenden Schritte in dieser Reihenfolge zu lernen:</p><ol><li><strong><a href="./channels-overview/">Übersicht des Mehrkanal-Systems</a></strong> - Verstehen Sie zuerst die Gesamtarchitektur und die Kanalkonzepte</li><li><strong><a href="./webchat/">WebChat-Oberfläche</a></strong> - Die einfachste Methode, ohne Konfiguration sofort loszulegen</li><li><strong>Wählen Sie einen gängigen Kanal</strong> - Wählen Sie basierend auf Ihren täglichen Gewohnheiten: <ul><li>Tägliches Chatten → <a href="./whatsapp/">WhatsApp</a> oder <a href="./telegram/">Telegram</a></li><li>Teamzusammenarbeit → <a href="./slack/">Slack</a> oder <a href="./discord/">Discord</a></li><li>macOS-Benutzer → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="mobile-integration" tabindex="-1">Mobile Integration <a class="header-anchor" href="#mobile-integration" aria-label="Permalink to &quot;Mobile Integration&quot;">​</a></h3><p>Wenn Sie Clawdbot auf Ihrem Handy verwenden möchten:</p><ol><li><strong><a href="./ios-node/">iOS-Node</a></strong> - Konfigurieren Sie die lokalen Funktionen auf iPhone/iPad</li><li><strong><a href="./android-node/">Android-Node</a></strong> - Konfigurieren Sie die lokalen Funktionen auf Android-Geräten</li><li><strong><a href="./macos-app/">macOS-Anwendung</a></strong> - Verwenden Sie die macOS-Anwendung als Steuerungszentrum</li></ol><h3 id="unternehmensweite-bereitstellung" tabindex="-1">Unternehmensweite Bereitstellung <a class="header-anchor" href="#unternehmensweite-bereitstellung" aria-label="Permalink to &quot;Unternehmensweite Bereitstellung&quot;">​</a></h3><p>Wenn Sie in einer Teamumgebung bereitstellen müssen:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Integration mit dem Team-Arbeitsbereich</li><li><strong><a href="./discord/">Discord</a></strong> - Einrichten eines Community-Servers</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Integration mit Google Workspace</li></ol><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie mit diesem Kapitel beginnen, wird empfohlen, Folgendes abzuschließen:</p><ul><li><strong><a href="./../start/getting-started/">Schnellstart</a></strong> - Führen Sie die Installation und die Grundkonfiguration von Clawdbot durch</li><li><strong><a href="./../start/onboarding-wizard/">Assistentenbasierte Konfiguration</a></strong> - Führen Sie die Grundeinstellungen für Gateway und Kanäle mit dem Assistenten durch</li></ul><div class="tip custom-block"><p class="custom-block-title">Hinweis</p><p>Wenn Sie die assistentengestützte Konfiguration bereits abgeschlossen haben, sind einige Kanäle möglicherweise bereits automatisch konfiguriert. Sie können wiederholte Konfigurationsschritte überspringen und direkt erweiterte Funktionen für bestimmte Kanäle prüfen.</p></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter erkunden:</p><ul><li><strong><a href="./../advanced/models-auth/">AI-Modell- und Authentifizierungskonfiguration</a></strong> - Konfigurieren Sie verschiedene AI-Modellanbieter</li><li><strong><a href="./../advanced/session-management/">Sitzungsverwaltung und Multi-Agent</a></strong> - Lernen Sie die Sitzungsisolierung und die Zusammenarbeit von Sub-Agenten</li><li><strong><a href="./../advanced/tools-browser/">Tools-System</a></strong> - Verwenden Sie Tools wie Browser-Automatisierung, Befehlsausführung usw.</li></ul><h2 id="haufig-gestellte-fragen" tabindex="-1">Häufig gestellte Fragen <a class="header-anchor" href="#haufig-gestellte-fragen" aria-label="Permalink to &quot;Häufig gestellte Fragen&quot;">​</a></h2><details class="details custom-block"><summary>Kann ich mehrere Kanäle gleichzeitig verwenden?</summary><p>Ja! Clawdbot unterstützt die gleichzeitige Aktivierung mehrerer Kanäle. Sie können auf verschiedenen Kanälen Nachrichten empfangen und senden, alle Nachrichten werden über den einheitlichen Gateway verarbeitet.</p></details><details class="details custom-block"><summary>Welcher Kanal wird am meisten empfohlen?</summary><p>Das hängt von Ihrem Anwendungsfall ab:</p><ul><li><strong>WebChat</strong> - Am einfachsten, keine Konfiguration erforderlich</li><li><strong>WhatsApp</strong> - Geeignet für Chats mit Freunden und Familie</li><li><strong>Telegram</strong> - Bot API stabil, geeignet für automatische Antworten</li><li><strong>Slack/Discord</strong> - Geeignet für Teamzusammenarbeit</li></ul></details><details class="details custom-block"><summary>Ist die Konfiguration von Kanälen kostenpflichtig?</summary><p>Die meisten Kanäle sind selbst kostenlos, aber einige Kanäle können Kosten verursachen:</p><ul><li>WhatsApp Business API - Kann Gebühren verursachen</li><li>Google Chat - Erfordert Google Workspace-Konto</li><li>Andere Kanäle - Normalerweise kostenlos, nur Beantragung von Bot-Token erforderlich</li></ul></details>',33)])])}const c=n(t,[["render",l]]);export{m as __pageData,c as default};
